changeSet.sql:
UPDATE media_file_instance mfi
  SET mfi.file_type = (
    SELECT mfv.file_type FROM media_file_version mfv WHERE mfv.id = mfi.media_file_version_id
  );
UPDATE media_file_instance mfi
  SET mfi.media_file_id = (
    SELECT mfv.media_file_id FROM media_file_version mfv WHERE mfv.id = mfi.media_file_version_id
  );

changeSet.rollback:
ALTER TABLE `media_file_instance`
  DROP FOREIGN KEY `media_file_instance_fk_media_file`,
  DROP INDEX `media_file_instance_fk_media_file_idx`;

changeSet.sql:
SET SQL_SAFE_UPDATES = 0;
UPDATE media_file_version mf
  SET mf.date_stored = (SELECT * FROM (SELECT DISTINCT(mf1.date_stored) FROM media_file_version mf1 WHERE mf1.filehash = mf.filehash AND mf1.date_stored IS NOT NULL) AS t)
  WHERE mf.date_stored IS NULL;
UPDATE media_file_version mf
  SET mf.date_stored_local = (SELECT * FROM (SELECT DISTINCT(mf1.date_stored_local) FROM media_file_version mf1 WHERE mf1.filehash = mf.filehash AND mf1.date_stored_local IS NOT NULL) AS t)
  WHERE mf.date_stored_local IS NULL;
UPDATE media_file_version mf
  SET mf.date_stored_utc = (SELECT * FROM (SELECT DISTINCT(mf1.date_stored_utc) FROM media_file_version mf1 WHERE mf1.filehash = mf.filehash AND mf1.date_stored_utc IS NOT NULL) AS t)
  WHERE mf.date_stored_utc IS NULL;
UPDATE media_file_version mf
  SET mf.date_stored_tz = (SELECT * FROM (SELECT DISTINCT(mf1.date_stored_tz) FROM media_file_version mf1 WHERE mf1.filehash = mf.filehash AND mf1.date_stored_tz IS NOT NULL) AS t)
  WHERE mf.date_stored_tz IS NULL;
UPDATE media_file_version mf
  SET mf.date_stored_tz = 'Europe/Berlin'
  WHERE mf.date_stored_tz IN ('+01:00', '+02:00');
